var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"사원의 절반이 날아가 버렸군…….","JPN":"寺院の半分が吹っ飛んでしまったな……","ENG":"Half of the temple has been obliterated...","TWN":"一半的修道院都被蒸發了……"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"엄청난 위력이야. 마지막까지 이런 비장의 수를 숨기고 있었다니…….","JPN":"凄まじい威力だ。最後までこんな奥の手を隠していたとは……","ENG":"Such incredible power. I can't believe he kept a secret weapon like this until the end...","TWN":"好強的威力。沒想到竟然把這樣的殺手鐧藏到了最後……"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"그보다 이런 폭발에 휘말렸다면 두 사람은 아마도…… ","JPN":"それよりこんな爆発に巻き込まれたということは、おそらくあの二人は…… ","ENG":"And the two who got caught up in that explosion should be...","TWN":"比起這個，如果被這樣的爆炸波及到，那兩個人恐怕已經……"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"으음?","JPN":"うむ？","ENG":"Hmm?","TWN":"額嗯？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……또 날 속였군요, 애버라인.","JPN":"……また私を騙しましたね、アバーライン。","ENG":"...You fooled me again, Abberline.","TWN":"……你又騙我！艾伯林！"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이 정도로 위험하다는 말은 없었잖아요! 드레스가 타버려서 엉망이 되어버렸다고요!","JPN":"こんなに危険だなんて聞いてません！　ドレスが焦げてめちゃくちゃになったじゃないですか！","ENG":"You didn't say that it would be this dangerous! Look at my dress! It's all burnt and a mess!","TWN":"沒說會這麼危險啊！我的裙子都燒壞了，變得一團糟了！"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 이해해주게. 스완.","JPN":"はは、理解してくれ。スワン。","ENG":"Haha, forgive me, Swan.","TWN":"哈哈，請理解一下，史旺。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"교수의 마도구에 대해 사실대로 말하면, 자네의 연기가 흔들릴지도 몰랐거든.","JPN":"教授の魔道具について本当のことを話したら、君の演技が揺らいでしまうかもしれないからな。","ENG":"But if I told you about Professor's Curio, I thought your acting would falter.","TWN":"我擔心如實說出，可能會影響你的演技。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"정말이지! 대체 절 뭐라고 생각하는 건가요!","JPN":"もう！　私をなんだと思ってるんですか！","ENG":"Ugh! Who do you think I am?!","TWN":"呃！你到底把我當成什麼了！"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"저는 런던 최고의 프리마돈나라고요! 겨우 이 정도 <color=#ffd34c>각본</color>도 소화 못할 리 없잖아요!","JPN":"私はロンドン最高のプリマドンナ！　たかがこの程度の<color=#ffd34c>脚本</color>も演じられないわけないでしょう！","ENG":"I am London's best prima donna! You know there is no <color=#ffd34c>script</color> too difficult for me!","TWN":"我是倫敦最棒的女主角！區區這種程度的<color=#ffd34c>劇本</color>，我怎麼可能演不好！"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"하, 하하……. 잠시나마 자네 걱정을 했던 내가 바보였군, 친구.","JPN":"は、はは……少しでも君を心配した俺がバカだったな、友よ。","ENG":"Ha, haha... I was a fool to worry about you for even a moment, my friend.","TWN":"哈，哈哈……竟然一瞬間擔心你了，我真是個傻瓜，朋友。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 역시 물어봐 주는 게 예의겠지? 대체 어떻게 그 폭발에서 빠져나온 건가?","JPN":"だが、やはり聞いてやらないと失礼だろうな。いったいどうやってあの爆発から抜け出せたんだ？","ENG":"But I should still ask. How did you get away from that explosion?","TWN":"但還是問一下比較禮貌吧？你到底是怎麼從那場爆炸中逃出來的？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 간단한 이야기라네, 벗이여.","JPN":"ふふ、実に簡単な話だよ、旧友。","ENG":"Haha. Elementary, my dear friend.","TWN":"哈哈，很簡單的推理，我親愛的華生。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"나는 처음부터 궁지에 몰린 모리어티 교수가 스완을 노릴 것이라는 걸 알고 있었다네.","JPN":"私は最初から予想していたのさ。窮地に追い込まれたモリアーティ教授は、スワンを狙うだろうと。","ENG":"I knew from the start that the embattled Professor Moriarty would target Swan.","TWN":"我從一開始就知道被逼入絕境的莫里蒂教授會盯上史旺。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"모리어티 교수는 그녀가 나에게 있어서 중요한 존재라고 확신하고 있었으니까.","JPN":"モリアーティ教授は、彼女が私にとって大事な存在だと確信していたからな。","ENG":"Professor Moriarty was convinced that she was important to me.","TWN":"因為莫里蒂教授確定她對我來說是重要的存在。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 늘 그렇듯, 확신은 독이 되고 시야를 흐리게 만들지.","JPN":"だが、確信というものは、時に毒となり視野を狭くする。","ENG":"But, as always, confidence is poisonous and clouds judgment.","TWN":"但一如既往，確定會成為毒藥，使判斷變得模糊。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래서 미리 스완에게 이 사실을 알리고, 인질 연기를 지시해 둔 거라네.","JPN":"だから、あらかじめスワンにこの事実を伝え、人質の演技を指示しておいたのだ。","ENG":"I informed Swan of this fact ahead of time, and told her to act as a hostage.","TWN":"所以我提前告訴了史旺這個事實，並指示她配合人質表演。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"마도구가 발동하기 직전에 빈틈을 만들어 낼 수 있도록.","JPN":"魔道具が発動する直前に隙を作れるようにな。","ENG":"So that right before he activated the Curio, there would be an opening.","TWN":"這樣就可以在魔導具發動之前製造一個空隙。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"빈틈이라고?","JPN":"隙だと？","ENG":"An opening?","TWN":"空隙嗎？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"거울이에요.","JPN":"鏡です。","ENG":"It's the Mirror.","TWN":"這是面鏡子。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"거울로 무대 조명을 모방해서, 모리어티 교수가 스포트라이트를 받게 만들었죠.","JPN":"鏡で舞台の照明に模倣して、モリアーティ教授がスポットライトを浴びるようにしたんです。","ENG":"I used the Mirror to imitate the spotlight and shine it on Professor Moriarty.","TWN":"我用鏡子模仿了舞台燈光，讓莫里蒂教授成為了焦點。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"무대에서는 종종 그런 식으로 클라이맥스를 연출하기도 하거든요.","JPN":"舞台ではよくそのようにクライマックスを演出したりするんですよ。","ENG":"It's a frequent technique used to express the climax on stage.","TWN":"在舞台上，經常會用那種方式來製造高潮。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"그렇군. 그 섬광은 교수의 마도구가 아니라, 스완 양의 마도구였어.","JPN":"そうか。あのフラッシュは教授の魔道具ではなく、スワンさんの魔道具だったのだな。","ENG":"I see. So that flash wasn't from Professor's Curio, but from Swan's.","TWN":"原來如此。那道閃光不是教授，而是史旺的魔法道具造成的。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"무대 조명으로 잠시 교수의 눈을 멀게 만들어, 그 사이 자네가 스완 양을 구해냈군.","JPN":"舞台の照明でしばらく教授の目を暗まし、その間に君がスワンさんを助けたというわけか。","ENG":"After blinding him with the stage light, you went to save Swan.","TWN":"用舞台燈光暫時讓教授失明，這期間你救出了史旺。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 교수의 마도구는 실제로 발동했어. 그 폭발을 피할 수는 없었을 텐데?","JPN":"だが、教授の魔道具は実際に発動したのだ。その爆発を回避することはできなかったはずだが。","ENG":"But Professor's Curio did activate. So you couldn't have avoided that explosion.","TWN":"但是教授的魔導器確實啟動了。那次爆炸是無法躲避的吧？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"맞아. 그것만큼은 나도 어쩔 도리가 없었네.","JPN":"そう。それだけは私もどうすることもできなかった。","ENG":"You're correct. There was nothing I could do about that.","TWN":"沒錯。那件事我也無能為力。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래서 줄곧 아껴두었던 이 <color=#ffd34c>우산</color>을 쓰고 만 거지.","JPN":"だからずっと大事にしまっておいたこの<color=#ffd34c>傘</color>を使ってしまったんだ。","ENG":"So I had to use this <color=#ffd34c>Umbrella</color> that I've been saving all along.","TWN":"所以我才用了這把一直珍藏的<color=#ffd34c>傘</color>。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"잠깐, 그 우산이 마도구였다고? 그건 몰랐던 사실인데?","JPN":"待て、その傘って魔道具だったのか？　そんなの初耳たぞ？","ENG":"Wait. That umbrella is a Curio? I didn't know that.","TWN":"等一下，那把傘是魔導具？這我還真不知道。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"지금껏 나한테도 비밀로 하고 있었다는 건가?","JPN":"今まで、この俺にまで、秘密にしていたのか？","ENG":"Have you been keeping that a secret from me all this time?","TWN":"到現在為止也對我保密嗎？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……어쩐지 익숙한 상황이네.","JPN":"……何とも馴染みのあるシーンね。","ENG":"...For some reason, this feels familiar...","TWN":"……怎麼感覺這種情況很熟悉呢。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 자네도 아직 멀었군. 딱히 비밀로 한 적은 없어.","JPN":"はは、君もまだまだだな。別に秘密にしてはいない。","ENG":"Haha, you still have a long way to go. I didn't really keep it a secret, however.","TWN":"哈哈，你還差得遠呢。我可從來沒打算隱瞞什麼。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"생각해보게. 내가 왜 비도 안 오는데 번거롭게 매일 같이 우산을 챙겼겠나?","JPN":"考えてみたまえ。雨も降らないのに、どうして私が毎日傘を持っていたと思う？","ENG":"Think about it. Why would I carry an umbrella even if it wasn't raining outside?","TWN":"想想看吧。我為什麼每天都要帶著傘，明明沒有下雨呢？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"하긴. 자네는 항상 모리어티에게 목숨을 위협받고 있었으니까.","JPN":"確かに……君はいつもモリアーティから命を狙われていたからな。","ENG":"Yes. Moriarty has always been threatening your life.","TWN":"確實。你隨時有可能受到莫里蒂的威脅。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"결국, 그자의 마도구를 막아냈으니 그 마도구는 적절하게 쓰인 셈이로군.","JPN":"結局、あの者の魔道具を防御することができたのだから、その魔道具は正しく使われたということか。","ENG":"In the end, you blocked his Curio, so it appears you used it appropriately.","TWN":"最終，擋住了那傢伙的魔導具，這把傘也算是用得其所了。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다네.","JPN":"そのとおりだ。","ENG":"Correct.","TWN":"是啊。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"용도를 다했으니 이제 이건 평범한 우산일 뿐이겠지.","JPN":"使ってしまった以上、もうこれはただの傘に過ぎない。","ENG":"Since it has served its purpose, it is now just an ordinary umbrella.","TWN":"用途已盡，現在這不過是一把平凡的雨傘而已。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"그나저나 역시 자네는 대단하군.","JPN":"ところで、やはり君はすごいな。","ENG":"Anyway, you truly are astounding.","TWN":"話說回來，果然還是你厲害啊。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"그 사태로부터 벌써 삼 년이나 지났는데, 여전히 그대로야.","JPN":"あの事変からもう三年も経ったのに、相変わらずだ。","ENG":"It's been three years since that incident. And yet, you are still the same.","TWN":"那件事已經過去三年了，但你一切都還是老樣子。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 칭찬으로 듣겠네.","JPN":"はは、褒め言葉として受け取ろう。","ENG":"Haha, I'll take that as a compliment.","TWN":"呵呵，這句話，我就當是稱讚了。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 나 혼자서는 결코 모리어티 교수를 쓰러트릴 수 없었을 거야.","JPN":"だが、私一人では絶対モリアーティ教授を倒すことはできなかっただろう。","ENG":"But I couldn't have defeated Professor Moriarty on my own.","TWN":"沒錯，但僅憑我一人之力，絕對無法擊敗莫里蒂教授。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"어쩌면 여기서 목숨을 잃었을지도 모르지.","JPN":"もしかしたら、ここで命を落としていたのかもしれない。","ENG":"I could've died here for all I know.","TWN":"或許，我已經在這裡喪命了。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네와 그리고…… 스완이 없었다면 말이야.","JPN":"君と、そして……スワンがいなかったらな。","ENG":"If you... and Swan weren't here, that is.","TWN":"如果沒有你……和史旺的話。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그러니 두 사람의 헌신에 진심으로 경의를 표하지.","JPN":"だから、二人の献身に心から感謝する。","ENG":"Allow me to express my gratitude to both of you.","TWN":"所以，我真心地向你們兩人的奉獻表示敬意。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"돼, 됐거든요……!","JPN":"い、いいんですよ……！","ENG":"S-stop it...!","TWN":"停、停下……！"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"칭찬 같은 거 받아봤자, 하나도 기쁘지 않으니까!","JPN":"褒めてもらったって、別に全然嬉しくないですし！","ENG":"I'm not happy at all even if I get a compliment from you!","TWN":"就算被誇獎，我也一點都不高興！"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 말했잖아요, 이제 이건 당신 혼자만의 사건이 아니라고.","JPN":"それに言ったじゃないですか。もうこれはあなた一人だけの事件じゃないって。","ENG":"And like I said, this isn't just your case anymore.","TWN":"而且我已經說過了，這已經不是你一個人的案件了。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"아직 아무것도 해결된 게 없어요. 그러니까 그런 말은 사건이 끝나고 나서 하라고요.","JPN":"まだ何も解決していません。だからそういうことは事件が終わってから言ってください。","ENG":"Nothing has been resolved. So save those words for after it's all over.","TWN":"目前還沒有解決任何問題。所以這種話等案件徹底結束後再說吧。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"그러고보니 소개가 늦었군. 존 왓슨이라고 한다네.","JPN":"そういえば、自己紹介が遅くなったな。俺はジョン・ワトソンだ。","ENG":"Now that I think of it, I haven't introduced myself yet. I am John Watson.","TWN":"這麼說起來，我好像忘了自我介紹。我叫約翰·華生。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"전직 군인이자……. 그래, 자네의 선배 정도 되겠군.","JPN":"元軍人で……そう、君の先輩になるか。","ENG":"I am a former soldier... and yes, your senior, so to speak.","TWN":"前軍人……對，也算是你的前輩吧。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"선배라고요?","JPN":"先輩？","ENG":"Senior?","TWN":"前輩嗎？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"으음?","JPN":"うむ？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"친구, 자네 설마 아직…….","JPN":"友よ。君、まさかまだ……","ENG":"My friend, you still haven't–","TWN":"朋友，你該不會還沒告訴她……"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_NULL","text":{"KOREA":"애버라인 경위님! 수사 결과 보고드립니다!","JPN":"アバーライン警部補！　捜査結果をご報告します！","ENG":"Lieutenant Abberline! I am here to report back on the result of the investigation!","TWN":"艾伯林警官！向你報告調查結果！"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L37_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_NULL","text":{"KOREA":"현재 사원 곳곳을 수색하여 증거물을 확보하고 있지만, 명부는 찾을 수가 없습니다.","JPN":"現在寺院の至るところを捜索して証拠品を確保していますが、名簿は見つかりませんでした。","ENG":"We have searched the temple thoroughly and secured evidence, but there seems to be no list.","TWN":"為了搜查證據，目前正在搜查整個據點，但還沒有找到名冊。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_NULL","text":{"KOREA":"작전이 진행되는 동안, 사교도들이 명부를 가지고 사원을 빠져나간 것 같습니다.","JPN":"作戦が進行している間、邪教徒が名簿を持って寺院を抜け出したようです。","ENG":"It seems that one of the cult members took it and fled during the operation.","TWN":"似乎是行動期間，有邪教徒帶著名冊離開了修道院。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"……야단났군.","JPN":"……まいったな。","ENG":"...This is troublesome.","TWN":"……真是一團糟。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"친구, 이제 어쩔 생각이지?","JPN":"友よ、これからどうするつもりだ？","ENG":"My friend, what do you plan on doing now?","TWN":"朋友，現在怎麼辦？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"아쉽게도 나 역시 복수귀에 대해서는 그리 아는 게 많지 않아","JPN":"残念ながら、俺も復讐鬼についてはあまり知らない。","ENG":"Unfortunately, I don't know much about the Revenger.","TWN":"可惜的是，我對復仇鬼也不是很了解。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"너무 깊게 파고들었다간, 모리어티의 의심을 살 것 같아서 말이지.","JPN":"深入りしすぎると、モリアーティから怪しまれると思ってな。","ENG":"I thought Moriarty would catch on to me if I delved in too deep.","TWN":"如果挖得太深，可能會引起莫里蒂的懷疑。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아니, 잘 해주었어.","JPN":"いや、よくやってくれたよ。","ENG":"No, you did good.","TWN":"不，你這麼做很好。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"모리어티 교수는 철저한 남자야. 괜한 추궁을 했다간 자네 목숨이 위험했을 걸세.","JPN":"モリアーティ教授は徹底した男だ。無理やり追及すると君が危険に晒されただろう。","ENG":"Professor Moriarty is a meticulous man. If you questioned him, your life would have been in danger.","TWN":"莫里蒂教授是個一絲不苟的人。要是隨隨便便追問，你的性命可能會有危險。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 명부에 관한 것 또한 걱정할 필요 없네.","JPN":"そして名簿についても心配する必要はない。","ENG":"Also, you don't have to worry about the list.","TWN":"而且關於名冊的事也不用擔心。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"우리는 이미 그걸 손에 넣은 것과 다름없으니까.","JPN":"私たちはすでに手に入れたも同然だからな。","ENG":"We already have it.","TWN":"我們已經把它拿到手了。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"뭐라고……?","JPN":"何だと……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"흥, 런던 제일의 프리마돈나를 이렇게 험하게 부리는 사람도 없을 거예요.","JPN":"フンッ、ロンドン第一のプリマドンナをこんなにこき使うのはあなただけですよ。","ENG":"Hmph. There is no one who would treat London's best prima donna so harshly as you do.","TWN":"哼，在你之前，可沒人敢這麼粗魯地對待倫敦首席女主角。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"아무리 저라도 겨우 몇 초 사이에 천 명이 넘는 신도를 외우는 건, 쉽지 않았다고요.","JPN":"いくら私でもたった数秒で千人以上の信徒を暗記するのは、簡単じゃありませんでした。","ENG":"Even if it was me, memorizing a list of more than a thousand followers for just a few seconds wasn't easy.","TWN":"即使是我，在短短幾秒內記住上千名信徒的名字，也不是件容易的事。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"정말……! 정말로 힘들었어요……!","JPN":"本当に……！　本当に大変でしたよ……！","ENG":"It was really...! REALLY hard...!","TWN":"真的……！真的好累啊……！"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 수고했다네.","JPN":"はは、ご苦労だったな。","ENG":"Haha, great work.","TWN":"哈哈哈，辛苦了。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래서 혹여나 빠트린 정보가 있지는 않겠지?","JPN":"それで、見落とした情報はないだろうな？","ENG":"You didn't miss anything, did you?","TWN":"所以不會有遺漏的資訊吧？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"훗, 또 제 실력을 의심하시는군요.","JPN":"ふっ、また私の実力を疑ってるんですね。","ENG":"Pfft. You're doubting my skills again.","TWN":"哼，又在懷疑我的實力嗎？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"명부에 적힌 신도 1536명의 이름과 나이, 주소 그리고 생일까지…….","JPN":"名簿に書かれた信徒1536名の名前と年齢、住所、それに誕生日まで……","ENG":"The 1,536 cultists' name, address, and even their date of birth...","TWN":"名冊上記錄了1536名信徒的名字、年齡、地址以及生日……"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"하나도 빠짐없이 전부 기억하고 있답니다.","JPN":"何一つ見落とさずに全部覚えています。","ENG":"I have it all in my head.","TWN":"我全部都記得，一點也沒忘。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};